```ts
type BaseAppAvatarProps = {
  color?: AppAvatarColor;
  badge?: ReactNode;
} & Omit<AvatarProps, "variant">;

type DeprecatedAppAvatarSizeProps = {
  /** @deprecated Size values 12 and 28 are deprecated. */
  size: 12 | 28;
};

type ActiveAppAvatarSizeProps = {
  size?: Exclude<AppAvatarSize, 12 | 28>;
};

export type AppAvatarProps =
  | (BaseAppAvatarProps & DeprecatedAppAvatarSizeProps)
  | (BaseAppAvatarProps & ActiveAppAvatarSizeProps);
```

### What to check now
In your editor, test:

```tsx
<AppAvatar size={12} />
<AppAvatar size={28} />
<AppAvatar size={16} />
```

