import { Box } from "@mui/material";
import { Children, type ReactNode, cloneElement, isValidElement } from "react";

import type { AppAvatarSize } from "./appAvatar.types.ts";

const stackOffsetMap: Partial<Record<AppAvatarSize, number>> = {
  16: 6,
  20: 8,
  24: 8,
  28: 10,
  32: 10,
  40: 12,
  48: 16,
  56: 16,
  64: 20,
};

export type AppAvatarStackProps = {
  children: ReactNode;
  size?: AppAvatarSize;
};

export function AppAvatarStack({ children, size = 40 }: AppAvatarStackProps) {
  const offset = stackOffsetMap[size] ?? Math.round(size * 0.3);
  const containerSize = size + offset;
  const [primary, secondary] = Children.toArray(children)
    .slice(0, 2)
    .map((child) =>
      isValidElement(child)
        ? cloneElement(child, { size } as { size: AppAvatarSize })
        : child,
    );

  return (
    <Box
      sx={{
        position: "relative",
        minWidth: containerSize,
        minHeight: containerSize,
      }}
    >
      <Box sx={{ position: "absolute", top: 0, left: 0 }}>{primary}</Box>
      <Box sx={{ position: "absolute", bottom: 0, right: 0 }}>{secondary}</Box>
    </Box>
  );
}

